<?php namespace App\Repositories\Payroll;use App\Repositories\BaseRepository;use App\Models\Payroll\OvertimeRecord;use Illuminate\Database\Eloquent\Collection;use Illuminate\Pagination\LengthAwarePaginator;class OvertimeRecordRepository extends BaseRepository{    public function __construct(OvertimeRecord $model)    {        $this->model = $model;        parent::__construct($model);    }    public function findByEmployee(int $employeeId): Collection    {        return $this->findByField('employee_id', $employeeId);    }    public function getByDate(string $date): Collection    {        return $this->query()->whereDate('date', $date)->get();    }    public function getByDateRange(string $startDate, string $endDate): Collection    {        return $this->query()->whereBetween('date', [$startDate, $endDate])->get();    }    public function getByMonth(int $month, int $year): Collection    {        return $this->query()->whereMonth('date', $month)->whereYear('date', $year)->get();    }    public function getByStatus(string $status): Collection    {        return $this->findByField('status', $status);    }    public function getPendingApprovals(): Collection    {        return $this->query()->where('status', 'pending')->get();    }    public function approve(int $id, ?string $approvedBy = null): bool    {        $data = ['status' => 'approved', 'approved_at' => now()];        if ($approvedBy) {            $data['approved_by'] = $approvedBy;        }        return $this->update($id, $data);    }    public function reject(int $id, string $reason): bool    {        return $this->update($id, ['status' => 'rejected', 'rejection_reason' => $reason]);    }    public function getTotalOvertimeHours(int $employeeId, int $month, int $year): float    {        return $this->query()->where('employee_id', $employeeId)->whereMonth('date', $month)->whereYear('date', $year)->where('status', 'approved')->sum('overtime_hours');    }    public function getTotalOvertimePay(int $employeeId, int $month, int $year): float    {        return $this->query()->where('employee_id', $employeeId)->whereMonth('date', $month)->whereYear('date', $year)->where('status', 'approved')->sum('overtime_amount');    }}